      // Turn block closers + breaks into a sentence boundary so headings,
      // paragraphs, and list items don't smash into following content.
      .replace(/<\/(p|h[1-6]|li|div|tr|section|article)>/gi, '. ')
      .replace(/<br\s*\/?\s*>/gi, '. ')
      // Strip remaining tags.
      .replace(/<[^>]*>/g, ' ')
      // Decode the entities LinkedIn most commonly emits.
      .replace(/&nbsp;/g, ' ')
      .replace(/&amp;/g, '&')
      .replace(/&lt;/g, '<')
      .replace(/&gt;/g, '>')
      .replace(/&quot;/g, '"')
      .replace(/&#39;/g, "'")
      // Collapse stutters from empty blocks ("..  .. ") into one ". ".
      .replace(/(\s*\.\s*){2,}/g, '. ')
      .replace(/\s+/g, ' ')
      .trim();
  } else if (job.descriptionText) {
    description = String(job.descriptionText);
  }
  description = description.slice(0, 700);

  // Prefer the LinkedIn job page (job.link) over the offsite applyUrl: the
  // applyUrl often points to the company's generic careers page (e.g.
  // homerun.co/#vacancies) rather than the specific role, and routing
  // through LinkedIn keeps the source clearly visible to the user.
  const applyUrl = job.link || job.applyUrl || '';
  const id = job.id || job.refId || `linkedin-${idx}`;

  // Dedupe by id AND by title+company (LinkedIn often reposts same role w/ new id)
  const fuzzyKey = `${(job.title||'').trim().toLowerCase()}|${(job.companyName||'').trim().toLowerCase()}`;
  if (seen.has(id) || seen.has(fuzzyKey)) return acc;
  seen.add(id);
  seen.add(fuzzyKey);

  acc.push({
    id,
    title: job.title || '',
    company: job.companyName || '',
    location: job.location || '',
    salary_min: salaryMin,
    salary_max: salaryMax,
    description,
    apply_url: applyUrl,
    posted_date: job.postedAt || '',
    source: 'LinkedIn',
    // Structured workplace + employment data from LinkedIn (for result badges).
    workplace_type: (Array.isArray(job.workplaceTypes) && job.workplaceTypes.length) ? job.workplaceTypes[0] : null,
    employment_type: job.employmentType || null
  });

  return acc;
}, []);

return [{ json: { jobs } }];

// Pure data prep for the scoring step. No prompt strings here.
const items = $input.all();
const jobs = items[0]?.json?.jobs || [];
const upstream = $('Prepare Translation Input').first().json;
const careerTitle = upstream.raw_career_title || '';
const userLanguages = Array.isArray(upstream.user_languages) ? upstream.user_languages : [];

// Build a compact, human-readable summary the LLM can reason over.
// Example: "Dutch (native), English (fluent), Spanish (conversational)"
const languages_summary = userLanguages.length
  ? userLanguages.map(l => `${l.language} (${l.proficiency})`).join(', ')
  : 'unknown — assume English only';

const avoidList = Array.isArray(upstream.avoid_preferences) ? upstream.avoid_preferences : [];
const avoid_summary = avoidList.length ? avoidList.join('; ') : 'none specified';

// Alt titles the report suggested for this same career (e.g. 'Corporate AI Trainer'
// for 'Executive Education Lecturer, AI for Business'). The scorer treats matching
// any alt as equivalent to matching the primary — otherwise good alt-title jobs
// get unfairly penalized just for using a different real-world label.
const altTitles = Array.isArray(upstream.alternate_titles_db) ? upstream.alternate_titles_db : [];
const alt_titles_summary = altTitles.length ? altTitles.join('; ') : 'none';
const career_overview = typeof upstream.career_overview === 'string' ? upstream.career_overview : '';

if (jobs.length === 0) {
  return [{ json: { jobs: [], careerTitle, jobList: [], languages_summary, avoid_summary, alt_titles_summary, career_overview, skip_scoring: true } }];
}

const jobList = jobs.map((j, i) => ({
  i,
  title: j.title || '',
  company: j.company || '',
  desc: (j.description || '').slice(0, 600)
}));

return [{
  json: {
    jobs,
    careerTitle,
    jobList,
    languages_summary,
    avoid_summary,
    alt_titles_summary,
    career_overview,
    skip_scoring: false
  }
}];

// Parse Gemini's JSON output, merge scores onto jobs, sort by score desc,
// then filter out matches below the suitability threshold so the user only
// sees jobs worth their time.
// Minimum score to surface at all. 0-2 are dropped entirely; the frontend
// further partitions 3-5 into a collapsible "filtered" panel and 6+ into
// the main results.
const MIN_SUITABLE_SCORE = 3;

const items = $input.all();
const item = items[0] || {};
const llmText = item.json?.text || item.json?.output || '';

const prepItem = $('Prepare Scoring Input').first().json;
const jobs = prepItem.jobs || [];

if (prepItem.skip_scoring || jobs.length === 0) {
  return [{ json: { jobs } }];
}

let scores = [];
try {
  const cleaned = String(llmText).replace(/```(?:json)?/g, '').trim();
  const match = cleaned.match(/\{[\s\S]*\}/);
  if (match) {
    const parsed = JSON.parse(match[0]);
    scores = Array.isArray(parsed.scores) ? parsed.scores : [];
  }
} catch (err) {
  console.warn('Score parse failed, returning unscored jobs:', err.message);
  return [{ json: { jobs } }];
}

const scoreById = new Map(scores.map(s => [s.i, s]));
const scored = jobs.map((j, i) => {
  const s = scoreById.get(i);
  return {
    ...j,
    match_score: typeof s?.score === 'number' ? Math.max(0, Math.min(10, s.score)) : null,
    match_reason: typeof s?.reason === 'string' ? s.reason : null,
  };
});

// Sort: highest score first; tiebreak by posted_date desc
scored.sort((a, b) => {
  const sa = a.match_score ?? -1;
  const sb = b.match_score ?? -1;
  if (sa !== sb) return sb - sa;
  return String(b.posted_date || '').localeCompare(String(a.posted_date || ''));
});

// Quality gate — only suitable matches (5+ per rubric) reach the user.
// If scoring failed (match_score == null), keep the job rather than drop it,
// since the user already had to wait for the search and an unscored job is
// preferable to silently disappearing it.
const filtered = scored.filter(j => {
  if (j.match_score == null) return true;
  return j.match_score >= MIN_SUITABLE_SCORE;
});

return [{ json: { jobs: filtered } }];

// Pure data prep for the translation step. No prompt strings here —
// the Set node downstream owns the prompt template.
const input = $input.first().json.body || $input.first().json;
const ENGLISH_LOCALES = new Set(['us','gb','ca','au','nz','ie']);
const COUNTRY_NAMES = {
  us: 'United States', gb: 'United Kingdom', ca: 'Canada', au: 'Australia',
  nl: 'Netherlands', de: 'Germany', fr: 'France', be: 'Belgium',
  ch: 'Switzerland', at: 'Austria', ie: 'Ireland', se: 'Sweden',
  dk: 'Denmark', no: 'Norway', fi: 'Finland', es: 'Spain', it: 'Italy',
  pt: 'Portugal', pl: 'Poland', nz: 'New Zealand', sg: 'Singapore', in: 'India'
};

function cleanCareerTitle(raw) {
  if (!raw) return '';
  let cleaned = raw;
  cleaned = cleaned.replace(/\s*\([^)]*\)/g, '');
  cleaned = cleaned.split(/[—–|,]/)[0];
  cleaned = cleaned.replace(/\s+at\s+(?:a|an|the)\s+.+$/i, '');
  cleaned = cleaned.replace(/\s+to\s+(?:CEO|CTO|CFO|COO|CMO|the\s+\w+).*$/i, '');
  cleaned = cleaned.replace(/\s+for\s+(?:a|an|the)\s+.+$/i, '');
  cleaned = cleaned.replace(/\s+(?:and|&)\s+.+$/i, '');
  cleaned = cleaned.replace(/\//g, ' ');
  cleaned = cleaned.replace(/\s+/g, ' ').trim();
  cleaned = cleaned.replace(/[,.;:]+$/, '').trim();
  const words = cleaned.split(/\s+/).filter(Boolean);
  if (words.length >= 4) cleaned = words.slice(-2).join(' ');
  return cleaned;
}

let countryCodes = Array.isArray(input.country_codes) && input.country_codes.length > 0
  ? input.country_codes
  : input.country_code ? [input.country_code] : ['us'];
countryCodes = [...new Set(countryCodes.map(c => String(c).toLowerCase().trim()))].slice(0, 2);

const reportId = input.report_id || null;
const altTitlesDb = Array.isArray(input.alternate_titles_db) ? input.alternate_titles_db : [];
const rawTitle = input.career_title || '';
const cleanedTitle = cleanCareerTitle(rawTitle);
const nonEnglish = countryCodes.filter(c => !ENGLISH_LOCALES.has(c));

// Pre-format the country list for the prompt template (so the Set node stays
// simple: one expression interpolation, no loops).
const country_lines_for_prompt = nonEnglish
  .map(c => `- ${c}: ${COUNTRY_NAMES[c] || c}`)
  .join('\n');

// Forward user_languages so downstream scoring can use them
const userLanguages = Array.isArray(input.user_languages) ? input.user_languages : [];

return [{
  json: {
    raw_career_title: rawTitle,
    report_id: reportId,
    alternate_titles_db: altTitlesDb,
    user_languages: userLanguages,
    cleaned_career_title: cleanedTitle,
    country_codes: countryCodes,
    non_english_countries: nonEnglish,
    country_lines_for_prompt,
    location: input.location || '',
    work_arrangement: input.work_arrangement || 'any',
    job_commitment: input.job_commitment || 'any',
    avoid_preferences: Array.isArray(input.avoid_preferences) ? input.avoid_preferences : [],
    alt_titles_summary: altTitlesDb.length ? altTitlesDb.join('; ') : 'none',
    career_overview: typeof input.career_overview === 'string' ? input.career_overview : '',
    skip_translation: nonEnglish.length === 0 || !cleanedTitle
  }
}];
